func convert[T any](input marshaler) (*T, error) {
	data, err := input.Marshal()
	if err != nil {
		return nil, err
	}

	var output T
	um, ok := any(&output).(unmarshaler)
	if !ok {
		return nil, errors.New("the output type doesn't implement unmarshaler interface")
	}

	err = um.Unmarshal(data)
	if err != nil {
		return nil, err
	}

	return &output, nil
}
